DELIMITER //

CREATE PROCEDURE add_new_order(
	p_name VARCHAR(100),
	p_price INT,
	p_agreement_ID INT,
	p_status binary,
	p_date_s datetime,
	p_date_f datetime
	
)
BEGIN

	IF p_agreement_id NOT IN (SELECT id FROM agreement) THEN
		SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Договор не найден';
	END IF;

	INSERT INTO `order` (order_name, price, agreement_id, status, date_start, date_finish)
    VALUES (p_name, p_price, p_agreement_id, p_status, p_date_s, p_date_f);
END //

DELIMITER ;


