CREATE PROCEDURE add_new_agreement(
	arg_name VARCHAR(100),
	arg_client_id INT,
	arg_date DATETIME,
	arg_Empl_id INT,
	o_name VARCHAR(100),
	o_price INT,
	o_agreement_ID INT,
	o_status binary,
	o_date_s datetime,
	o_date_f datetime
)
BEGIN
		
	DECLARE new_agreement_id INT;

	INSERT INTO agreement (name, client_id, date, Employee_id)
    VALUES (arg_name, arg_client_id, arg_date, arg_Empl_id);

	SET new_agreement_id = LAST_INSERT_ID();

	INSERT INTO `order` (order_name, price, agreement_id, status, date_start, date_finish)
    VALUES (o_name, o_price, o_agreement_id, o_status, o_date_s, o_date_f);
END //

DELIMITER ;

