-- Задание 2.1

DELIMITER //

CREATE PROCEDURE OrderSummary(cl_name VARCHAR(100))

BEGIN
	
	SELECT cl.name AS 'ФИО', o.order_name AS 'Заказ',
    SUM(p.price * SC.quantity_in_sc) + SUM(tn.price_nanesenia * SC.quantity_in_sc) + MAX(SC.delivery_price) AS 'Итоговая сумма'
	FROM `order` AS o
	JOIN agreement AS agr ON o.agreement_id = agr.id
	JOIN Client AS cl ON agr.client_id = cl.id
	JOIN Shopping_Cart AS SC ON o.id = SC.order_id
	JOIN Products p ON SC.products_id = p.id
	JOIN type_nanesenia AS tn ON SC.nanesenia_id = tn.id WHERE cl.name = cl_name
	GROUP BY o.id;

END //

DELIMITER ;

CALL OrderSummary("ИП Иванов Алексей");
CALL OrderSummary("ИП Лебедева Екатерина");
CALL OrderSummary("ИП Лебеде Екатерина");


-- Задание 2.2
DELIMITER //

CREATE PROCEDURE CheckOrderDate(target_date DATE)
BEGIN
    SELECT 
        o.order_name AS 'Название заказа',
        o.status AS 'Статус',
        o.date_start AS 'Дата начала',
        o.date_finish AS 'Дата завершения'
    FROM `order` AS o
    JOIN agreement a ON o.agreement_id = a.id
    WHERE o.status = 0                          
        OR (o.date_finish IS NULL)             
        OR (o.date_finish > target_date)       
    ORDER BY o.id;
END //

DELIMITER ;

CALL CheckOrderDate('2025-10-30');
CALL CheckOrderDate('2026-01-10');

-- Задание 2.3

DELIMITER //

CREATE PROCEDURE CheckVolume(product_name VARCHAR(100))
BEGIN
    SELECT 
        p.name AS 'Товар',
        SUM(sc.quantity_in_sc) AS 'Продано'
    FROM Products AS p
    JOIN Shopping_Cart AS sc ON p.id = sc.Products_id
    JOIN `order` o ON sc.Order_id = o.id
    WHERE p.name = product_name
        AND o.status = 1
    GROUP BY p.name;
END //

DELIMITER ;

CALL CheckVolume('Samsung Galaxy S3 mini');

SELECT * FROM shopping_cart;

-- Задание 2.4
DELIMITER //

CREATE PROCEDURE CheckSum(agreement_name VARCHAR(100))
BEGIN
    SELECT 
        a.name AS 'Договор',
        c.name AS 'Клиент',
        SUM(sc.quantity_in_sc * p.price + sc.quantity_in_sc * tn.price_nanesenia + sc.delivery_price) AS 'Общая сумма'
    FROM agreement a
    JOIN client c ON a.client_id = c.id
    JOIN `order` o ON a.id = o.agreement_id AND o.status = 1
    JOIN Shopping_Cart sc ON o.id = sc.Order_id
    JOIN Products p ON sc.Products_id = p.id
    JOIN type_nanesenia tn ON sc.nanesenia_id = tn.id
    WHERE a.name = agreement_name
    GROUP BY a.name, c.name;
END //

DELIMITER ;

CALL CheckSum('Договор №001');
CALL CheckSum('Договор №005');

SELECT * from agreement;

